"use client";
import { useState } from "react";
import { supabase } from "../../../lib/supabaseClient";

interface TaskPhotoUploadProps {
  taskId: number;
  onUploaded: (url: string) => void;
}

export default function TaskPhotoUpload({ taskId, onUploaded }: TaskPhotoUploadProps) {
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  async function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setMessage(null);
    try {
      const filePath = `tasks/${taskId}/${Date.now()}_${file.name}`;
      const { error: uploadError } = await supabase.storage.from("photos").upload(filePath, file, { upsert: false });
      if (uploadError) {
        throw uploadError;
      }
      const { data } = supabase.storage.from("photos").getPublicUrl(filePath);
      onUploaded(data.publicUrl);
      setMessage("Photo attached");
    } catch (err: unknown) {
      if (err instanceof Error) {
        setMessage(`Upload failed: ${err.message}`);
      } else {
        setMessage("Upload failed");
      }
    } finally {
      setUploading(false);
    }
  }

  return (
    <label className="text-sm font-medium text-indigo-600 cursor-pointer">
      <span className="underline">Upload photo</span>
      <input
        type="file"
        accept="image/*"
        className="hidden"
        onChange={handleFileChange}
        disabled={uploading}
      />
      {uploading && <span className="ml-2 text-gray-500">Uploading...</span>}
      {message && <div className="text-xs text-gray-500 mt-1">{message}</div>}
    </label>
  );
}
